const GROUP_MAP = {
  '120363426390515923@g.us': { context: 'angelfly', label: 'Angel Fly' },
  '120363420996892188@g.us': { context: 'garlic', label: 'Garlic N Lemon' },
  '120363422948599063@g.us': { context: 'ernesto', label: 'Ernesto' }
};

const normalize = (v) => String(v || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9\s]/g, ' ').trim();

// Get today in BRT (UTC-3)
const now = new Date();
const brt = new Date(now.getTime() - 3 * 3600000);
const today = brt.toISOString().slice(0, 10);

// Collect tasks & tickets
const collectRecords = (items) => {
  const all = [];
  for (const item of items) {
    const j = item.json;
    if (Array.isArray(j)) { for (const r of j) { if (r && r.id) all.push(r); } }
    else if (j && j.id) all.push(j);
    else if (Array.isArray(j?.data)) { for (const r of j.data) { if (r && r.id) all.push(r); } }
  }
  return all;
};

const tasks = collectRecords($('Fetch All Tasks').all());
const tickets = collectRecords($('Fetch All Tickets').all());

const isOpen = (s) => !['closed','completed','cancelled','resolved','done'].includes(normalize(s));
const dateOf = (obj) => (obj?.deadline || obj?.due_date || obj?.created_date || '').slice(0, 10);

const todayTasks = tasks.filter(t => isOpen(t.status) && dateOf(t) === today);
const openTasks = tasks.filter(t => isOpen(t.status));
const todayTickets = tickets.filter(t => isOpen(t.status) && dateOf(t) === today);
const openTickets = tickets.filter(t => isOpen(t.status));

const formatItem = (x, field) => {
  const name = x[field] || x.title || x.subject || '(sem título)';
  const assignee = x.assigned_to_name || '';
  const dl = x.deadline || x.due_date || '';
  const pr = x.priority || '';
  let line = '• ' + name;
  if (pr) line += ' [' + pr + ']';
  if (assignee) line += ' 👤 ' + assignee;
  if (dl) line += ' 📅 ' + dl;
  return line;
};

const groupMatch = (obj, ctx) => {
  const pn = normalize(obj?.project_name || '');
  const cn = normalize(obj?.client_name || '');
  const combined = pn + ' ' + cn;
  if (ctx === 'garlic') return /garlic|gnl/.test(combined);
  if (ctx === 'ernesto') return /ernesto/.test(combined);
  if (ctx === 'angelfly') return /angel\s*fly|cockpit/.test(combined);
  return true;
};

const results = [];

for (const [chatId, group] of Object.entries(GROUP_MAP)) {
  const gTodayTasks = todayTasks.filter(t => groupMatch(t, group.context));
  const gOpenTasks = openTasks.filter(t => groupMatch(t, group.context));
  const gTodayTickets = todayTickets.filter(t => groupMatch(t, group.context));
  const gOpenTickets = openTickets.filter(t => groupMatch(t, group.context));

  let msg = '☀️ *Bom dia, equipe ' + group.label + '!*\nVamos retomar as atividades. Segue o que temos para hoje:\n';

  if (gTodayTasks.length > 0) {
    msg += '\n🧩 *Tasks de Hoje (' + gTodayTasks.length + '):*\n';
    msg += gTodayTasks.map(t => formatItem(t, 'title')).join('\n');
  }

  if (gTodayTickets.length > 0) {
    msg += '\n\n🎫 *Tickets de Hoje (' + gTodayTickets.length + '):*\n';
    msg += gTodayTickets.map(t => formatItem(t, 'subject')).join('\n');
  }

  if (gTodayTasks.length === 0 && gTodayTickets.length === 0) {
    msg += '\n✨ Nenhuma task ou ticket programado especificamente para hoje.';
  }

  msg += '\n\n📊 *Resumo Geral:*';
  msg += '\n• Tasks abertas: ' + gOpenTasks.length;
  msg += '\n• Tickets abertos: ' + gOpenTickets.length;
  msg += '\n\nBom trabalho! 💪';

  results.push({ json: { number: chatId, text: msg, groupLabel: group.label } });
}

return results;
